  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is AnchorEvidence &&
          runtimeType == other.runtimeType &&
          seqAnchorHeight == other.seqAnchorHeight &&
          btcLegHeight == other.btcLegHeight &&
          btcTip == other.btcTip &&
          anchorStatus == other.anchorStatus &&
          depth == other.depth &&
          ok == other.ok;
