/// A wallet transaction history row.
class TxRow {
  final String txid;
  final int? height;
  final BigInt? timestamp;

  /// "incoming" | "outgoing" | "issuance" | "reissuance" | "burn" | "redeposit" | "unknown".
  final String kind;
  final BigInt fee;

  /// The asset id (hex) the network fee was paid in. Sequentia's open fee market
  /// lets the fee be ANY accepted asset, not just the policy asset, so the UI
  /// must label the fee with its real asset instead of assuming tSEQ. Falls back
  /// to the policy asset when the tx has no explicit fee output (fee == 0).
  final String feeAsset;
  final List<AssetDelta> deltas;

  const TxRow({
    required this.txid,
    this.height,
    this.timestamp,
    required this.kind,
    required this.fee,
    required this.feeAsset,
    required this.deltas,
  });

  @override
  int get hashCode =>
      txid.hashCode ^
      height.hashCode ^
      timestamp.hashCode ^
      kind.hashCode ^
      fee.hashCode ^
      feeAsset.hashCode ^
      deltas.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is TxRow &&
          runtimeType == other.runtimeType &&
          txid == other.txid &&
          height == other.height &&
          timestamp == other.timestamp &&
          kind == other.kind &&
          fee == other.fee &&
          feeAsset == other.feeAsset &&
          deltas == other.deltas;
}

